#!/usr/bin/env python3\n\"\"\"\nTest Enhanced Product Search with 3-Step Gemini Workflow\nTesting: Intent Detection -> BDStall API -> AI Response Formatting\n\"\"\"\nimport os\nfrom enhanced_product_search import EnhancedProductSearch\nfrom bdstall_chatbot_system import BDStallChatbotSystem\n\ndef test_enhanced_search_standalone():\n    \"\"\"Test the enhanced product search directly\"\"\"\n    print(\"🧪 Testing Enhanced Product Search (Standalone)\")\n    print(\"=\" * 55)\n    \n    # Check if Gemini API key is available\n    gemini_key = os.getenv('GEMINI_API_KEY')\n    if not gemini_key:\n        print(\"❌ GEMINI_API_KEY not found. Testing with fallback mode.\")\n    \n    try:\n        # Initialize enhanced search\n        searcher = EnhancedProductSearch(gemini_api_key=gemini_key)\n        \n        # Test queries\n        test_queries = [\n            \"web cam lagbe\",\n            \"hp laptop price koto?\",\n            \"mobile phone ache?\",\n            \"wireless mouse kinte chai\",\n            \"gaming headphone dekhaite paren?\"\n        ]\n        \n        for i, query in enumerate(test_queries, 1):\n            print(f\"\\n📋 Test {i}: '{query}'\")\n            print(\"-\" * 40)\n            \n            result = searcher.enhanced_product_search(query)\n            \n            print(f\"✅ Success: {result.get('success')}\")\n            print(f\"📝 Response: {result.get('response', 'No response')[:150]}...\")\n            print(f\"📦 Products Found: {result.get('products_found', 0)}\")\n            \n            if result.get('intent_detected'):\n                intent = result['intent_detected']\n                print(f\"🧠 Intent: {intent.get('intent')} (confidence: {intent.get('confidence', 0):.2f})\")\n                print(f\"🔍 Search Terms: {intent.get('search_terms')}\")\n            \n            if result.get('top_products'):\n                print(\"🛍️ Top Products:\")\n                for j, product in enumerate(result['top_products'][:2], 1):\n                    title = product.get('title', 'No title')[:50]\n                    price = product.get('price', 'No price')\n                    print(f\"   {j}. {title} - {price}\")\n    \n    except Exception as e:\n        print(f\"❌ Error: {e}\")\n        import traceback\n        traceback.print_exc()\n\ndef test_enhanced_search_in_chatbot():\n    \"\"\"Test enhanced product search integrated in full chatbot system\"\"\"\n    print(\"\\n\\n🤖 Testing Enhanced Search in Full Chatbot System\")\n    print(\"=\" * 55)\n    \n    try:\n        # Initialize chatbot system\n        chatbot = BDStallChatbotSystem()\n        print(\"✅ Chatbot system initialized\")\n        \n        # Test product search queries\n        product_queries = [\n            \"web cam lagbe\",\n            \"laptop cheap price range e ache?\",\n            \"wireless headphone dekhaite paren?\"\n        ]\n        \n        for i, query in enumerate(product_queries, 1):\n            print(f\"\\n🧪 Chatbot Test {i}: '{query}'\")\n            print(\"-\" * 40)\n            \n            result = chatbot.process_message(\n                user_id=\"test_user_product_search\",\n                message=query,\n                channel=\"web\"\n            )\n            \n            print(f\"✅ Success: {result.get('success')}\")\n            print(f\"📝 Response: {result.get('response', 'No response')[:150]}...\")\n            \n            if 'processing_info' in result:\n                info = result['processing_info']\n                print(f\"📊 Source: {info.get('source', 'unknown')}\")\n                print(f\"⏱️ Time: {info.get('processing_time_seconds', 'unknown')} seconds\")\n                \n                if info.get('enhanced_search'):\n                    print(\"🚀 Used Enhanced AI Search!\")\n                elif info.get('search_method'):\n                    print(f\"🔍 Search Method: {info.get('search_method')}\")\n    \n    except Exception as e:\n        print(f\"❌ Error: {e}\")\n        import traceback\n        traceback.print_exc()\n\ndef main():\n    \"\"\"Run all tests\"\"\"\n    print(\"🚀 Enhanced Product Search Testing Suite\")\n    print(\"=\" * 60)\n    print(\"Testing 3-Step Workflow: Intent Detection → API Search → AI Response\")\n    print()\n    \n    # Test standalone enhanced search\n    test_enhanced_search_standalone()\n    \n    # Test integrated in chatbot system\n    test_enhanced_search_in_chatbot()\n    \n    print(\"\\n🎉 All tests completed!\")\n    print(\"\")\n    print(\"💡 If you see Gemini API errors, set GEMINI_API_KEY environment variable\")\n    print(\"   The system will fall back to basic search without AI enhancement\")\n\nif __name__ == \"__main__\":\n    main()